/**
 * CMS Global Helpers
 * ──────────────────
 * Loaded via composer.json autoload.files.
 * Available anywhere: controllers, views, services, Blade.
 */

if (! function_exists('setting')) {
    /**
     * Get a global CMS setting value.
     *
     * Examples:
     *   setting('site_name')  → 'My College'
     *   setting('missing_key', 'fallback') → 'fallback'
     */
    function setting(string $key, mixed $default = null): mixed
    {
        try {
            return app(\App\Services\SettingsService::class)->get($key, $default);
        } catch (\Throwable) {
            return $default;
        }
    }
}

if (! function_exists('setting_url')) {
    /**
     * Get a setting value that is a media path and resolve it to a full URL.
     *
     * Examples:
     *   setting_url('site_logo')  → 'https://cdn.example.com/logo.png'
     *   setting_url('site_logo', asset('images/default-logo.png'))
     */
    function setting_url(string $key, string $default = ''): string
    {
        try {
            return app(\App\Services\SettingsService::class)->url($key, $default);
        } catch (\Throwable) {
            return $default;
        }
    }
}

if (! function_exists('cms_media_url')) {
    /**
     * Resolve a media file_path (local or cloud) to a public URL.
     *
     * Examples:
     *   cms_media_url('/media/logo.png')  → 'https://yourdomain.com/media/logo.png'
     *   cms_media_url('https://…')        → 'https://…'   (pass-through)
     *   cms_media_url(null)               → ''
     */
    function cms_media_url(?string $path, string $default = ''): string
    {
        if (! $path) return $default;
        if (str_starts_with($path, 'http')) return $path;
        return asset(ltrim($path, '/'));
    }
}

if (! function_exists('cmsWidgetIcon')) {
    /**
     * Render a Bootstrap Icon name (e.g. "bi-bar-chart-fill" or "bar-chart-fill")
     * as a self-hosted inline SVG string — no Bootstrap Icons CDN needed.
     *
     * The SVG paths are defined in /assets/js/cms-icons.js (client-side) and
     * mirrored here for server-side Blade rendering.
     */
    function cmsWidgetIcon(string $biClass, int $size = 18, string $color = 'currentColor'): string
    {
        // Normalise: strip "bi-" or "bi " prefix
        $name = preg_replace('/^bi[-\s]/', '', trim($biClass));

        $paths = cms_svg_paths($name);

        return sprintf(
            '<svg xmlns="http://www.w3.org/2000/svg" width="%d" height="%d" viewBox="0 0 16 16" fill="%s" style="display:inline-block;vertical-align:-0.125em;flex-shrink:0">%s</svg>',
            $size, $size,
            htmlspecialchars($color, ENT_QUOTES),
            $paths
        );
    }
}

